create table if not exists public.buy_fee_rules (id uuid primary key default gen_random_uuid(), store_id uuid references public.stores(id) on delete cascade, effective_month date not null, brand text not null, make_pattern text not null, amount numeric not null check (amount >= 0), active boolean not null default true, created_at timestamptz not null default now());
create index if not exists buy_fee_rules_lookup_idx on public.buy_fee_rules (effective_month, active, store_id);
create unique index if not exists buy_fee_rules_store_month_brand_uidx on public.buy_fee_rules (store_id, effective_month, lower(brand)) where store_id is not null;
create unique index if not exists buy_fee_rules_global_month_brand_uidx on public.buy_fee_rules (effective_month, lower(brand)) where store_id is null;
alter table public.buy_fee_rules enable row level security;
drop policy if exists buy_fee_rules_select on public.buy_fee_rules;
drop policy if exists buy_fee_rules_admin_manage on public.buy_fee_rules;
create policy buy_fee_rules_select on public.buy_fee_rules for select to authenticated using (true);
create policy buy_fee_rules_admin_manage on public.buy_fee_rules for all to authenticated using (public.current_role() = 'admin') with check (public.current_role() = 'admin');
insert into public.buy_fee_rules(store_id, effective_month, brand, make_pattern, amount, active) select s.id, '2026-01-01'::date, 'McLaren', '%McLaren%', 1500, true from public.stores s where s.name = 'O''Gara Beverly Hills' and not exists (select 1 from public.buy_fee_rules r where r.store_id = s.id and r.effective_month = '2026-01-01'::date and lower(r.brand) = 'mclaren');
update public.buy_fee_rules r set amount = 1500, make_pattern = '%McLaren%', active = true from public.stores s where r.store_id = s.id and s.name = 'O''Gara Beverly Hills' and r.effective_month = '2026-01-01'::date and lower(r.brand) = 'mclaren';
create or replace function public.buy_fee_amount(p_vehicle text, p_acv numeric, p_month date, p_store_id uuid) returns numeric language plpgsql stable security definer set search_path to 'public' as $function$ declare v_amount numeric; begin select r.amount into v_amount from public.buy_fee_rules r where r.active and r.effective_month <= date_trunc('month', coalesce(p_month, current_date))::date and (r.store_id is null or r.store_id = p_store_id) and coalesce(p_vehicle, '') ilike r.make_pattern order by case when r.store_id is not null and r.store_id = p_store_id then 0 else 1 end, r.effective_month desc, length(r.make_pattern) desc, r.created_at desc limit 1; return coalesce(v_amount, case when coalesce(p_acv, 0) > 99999 then 1000 else 500 end); end; $function$;
create or replace function public.refresh_commission_preview(p_month date default null,p_store_id uuid default null) returns jsonb language plpgsql security definer set search_path to 'public' as $function$ declare target_month date; sid uuid; v_run_id uuid; inserted_count integer:=0; spiff_count integer:=0; buy_fee_count integer:=0; flat_adjustment_count integer:=0; pct_adjustment_count integer:=0; begin target_month=date_trunc('month',coalesce(p_month,current_date))::date; sid=p_store_id; if sid is null and public.current_role()='manager' then sid=public.current_store_id(); end if; if exists(select 1 from public.commission_runs cr where cr.month=target_month and cr.store_id is not distinct from sid and cr.status in ('locked','paid')) then raise exception 'Commission run is locked or paid.'; end if; select cr.id into v_run_id from public.commission_runs cr where cr.month=target_month and cr.store_id is not distinct from sid and cr.status='preview' order by cr.refreshed_at desc nulls last,cr.created_at desc,cr.id desc limit 1; if v_run_id is not null then delete from public.commission_lines cl where cl.run_id in (select cr.id from public.commission_runs cr where cr.month=target_month and cr.store_id is not distinct from sid and cr.status='preview' and cr.id<>v_run_id); delete from public.commission_runs cr where cr.month=target_month and cr.store_id is not distinct from sid and cr.status='preview' and cr.id<>v_run_id; update public.commission_runs set refreshed_at=now(),created_by=auth.uid() where id=v_run_id; else insert into public.commission_runs(month,store_id,status,created_by,refreshed_at) values(target_month,sid,'preview',auth.uid(),now()) returning id into v_run_id; end if; delete from public.commission_lines where run_id=v_run_id; with participants as (select d.id deal_id,d.front_gross,d.stock_type,d.make,d.contract_date,d.store_id,d.raw_json,dp.employee_id,dp.split_pct,sum(dp.split_pct) over(partition by dp.employee_id) total_units from public.sales_deals d join public.deal_participants dp on dp.deal_id=d.id where date_trunc('month',d.contract_date)::date=target_month and coalesce(d.make,'')<>'' and coalesce(d.stock_number,'')<>'' and dp.employee_id is not null and (sid is null or d.store_id=sid)), calc as (select p.*,coalesce(pp.base_rate_pct,10) base_rate_pct,coalesce(pp.rate_cap_pct,25) rate_cap_pct,public.unit_rate_enhancement(p.total_units,target_month,p.store_id) unit_rate_pct,public.mini_amount(p.total_units,target_month,p.store_id) mini from participants p left join lateral public.default_pay_plan_for(p.employee_id,target_month) pp on true) insert into public.commission_lines(run_id,employee_id,deal_id,line_type,amount,explanation,source_table,source_id) select v_run_id,employee_id,deal_id,'deal_base',round(greatest(coalesce(front_gross,0)*split_pct*least(base_rate_pct+unit_rate_pct,rate_cap_pct)/100,mini*split_pct),2),concat('Base ',base_rate_pct,'% plus unit enhancer ',unit_rate_pct,'%, capped at ',rate_cap_pct,'%. Mini ',mini,'.'),'sales_deals',deal_id from calc; get diagnostics inserted_count=row_count; with sale_participants as (select d.id deal_id,d.raw_json,dp.employee_id,dp.split_pct from public.sales_deals d join public.deal_participants dp on dp.deal_id=d.id where date_trunc('month',d.contract_date)::date=target_month and coalesce(d.make,'')<>'' and coalesce(d.stock_number,'')<>'' and dp.employee_id is not null and (sid is null or d.store_id=sid)), spiffs as (select deal_id,employee_id,round(coalesce(public.money_to_numeric(public.json_text_any(raw_json,array['Salesperson Spiff Amount'])),0)*split_pct,2) amount from sale_participants) insert into public.commission_lines(run_id,employee_id,deal_id,line_type,amount,explanation,source_table,source_id) select v_run_id,employee_id,deal_id,'spiff',amount,'Tekion Salesperson Spiff Amount, split weighted.','sales_deals',deal_id from spiffs where amount<>0; get diagnostics spiff_count=row_count; with acquisition_participants as (select d.id deal_id,d.vehicle,d.store_id,d.acquisition_acv,dp.employee_id,dp.split_pct from public.sales_deals d join public.deal_participants dp on dp.deal_id=d.id where date_trunc('month',d.contract_date)::date=target_month and coalesce(d.make,'')='' and lower(coalesce(d.deal_type,'')) like '%acquisition%' and d.acquisition_acv is not null and dp.employee_id is not null and (sid is null or d.store_id=sid)) insert into public.commission_lines(run_id,employee_id,deal_id,line_type,amount,explanation,source_table,source_id) select v_run_id,employee_id,deal_id,'buy_fee',round(public.buy_fee_amount(vehicle,acquisition_acv,target_month,store_id)*split_pct,2),concat('Auto buy fee from acquisition vehicle ',coalesce(vehicle,'unknown'),' and ACV ',acquisition_acv,'. Split weighted.'),'sales_deals',deal_id from acquisition_participants; get diagnostics buy_fee_count=row_count; with resolved_adjustments as (select a.*,coalesce(a.employee_id,e.id) resolved_employee_id,coalesce(a.store_id,e.store_id) resolved_store_id from public.adjustments a left join public.employees e on (e.id=a.employee_id or (e.display_name=a.rep and (a.store_id is null or e.store_id is not distinct from a.store_id))) where a.month=target_month) insert into public.commission_lines(run_id,employee_id,deal_id,line_type,amount,explanation,source_table,source_id) select v_run_id,a.resolved_employee_id,d.id,a.category,round(coalesce(a.amount,0),2),a.note,'adjustments',a.id from resolved_adjustments a left join public.sales_deals d on d.deal_number=a.deal_number where (sid is null or a.resolved_store_id=sid) and a.resolved_employee_id is not null and a.amount is not null and a.pct is null; get diagnostics flat_adjustment_count=row_count; with resolved_adjustments as (select a.*,coalesce(a.employee_id,e.id) resolved_employee_id,coalesce(a.store_id,e.store_id) resolved_store_id from public.adjustments a left join public.employees e on (e.id=a.employee_id or (e.display_name=a.rep and (a.store_id is null or e.store_id is not distinct from a.store_id))) where a.month=target_month) insert into public.commission_lines(run_id,employee_id,deal_id,line_type,amount,explanation,source_table,source_id) select v_run_id,a.resolved_employee_id,sd.id,a.category,round(coalesce(sd.front_gross,0)*dp.split_pct*a.pct/100,2),concat(coalesce(a.note,a.category),' · ',a.pct,'% allocated to deal front gross.'),'adjustments',a.id from resolved_adjustments a join public.deal_participants dp on dp.employee_id=a.resolved_employee_id join public.sales_deals sd on sd.id=dp.deal_id where (sid is null or a.resolved_store_id=sid) and a.resolved_employee_id is not null and a.pct is not null and date_trunc('month',sd.contract_date)::date=target_month and coalesce(sd.make,'')<>'' and coalesce(sd.stock_number,'')<>'' and (a.deal_number is null or sd.deal_number=a.deal_number); get diagnostics pct_adjustment_count=row_count; return jsonb_build_object('run_id',v_run_id,'month',target_month,'deal_base_lines',inserted_count,'tekion_spiff_lines',spiff_count,'auto_buy_fee_lines',buy_fee_count,'flat_adjustment_lines',flat_adjustment_count,'pct_adjustment_lines',pct_adjustment_count,'adjustment_lines',flat_adjustment_count+pct_adjustment_count,'commission_lines',inserted_count+spiff_count+buy_fee_count+flat_adjustment_count+pct_adjustment_count); end; $function$;